import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

# 1. Load the results generated by your training script
try:
    df = pd.read_csv("baseline_experiment_results.csv")
except FileNotFoundError:
    print("❌ Error: 'baseline_experiment_results.csv' not found. Make sure train_baseline.py has finished running!")
    exit()

# 2. Set up the visual style
sns.set_theme(style="whitegrid")

# Create a wide figure to hold two subplots side-by-side
fig, axes = plt.subplots(1, 2, figsize=(16, 6))

# 3. Plot Training MSE (Left Chart)
sns.barplot(
    data=df, 
    x='seq_len', 
    y='train_mse', 
    hue='architecture', 
    palette='Blues_d', 
    ax=axes[0]
)
axes[0].set_title('Training Error (Underfitting vs. Overfitting)', fontsize=14, fontweight='bold')
axes[0].set_xlabel('Sequence Length (Days)', fontsize=12)
axes[0].set_ylabel('Train MSE', fontsize=12)
axes[0].legend(title='Hidden Layers')

# 4. Plot Testing MSE (Right Chart)
sns.barplot(
    data=df, 
    x='seq_len', 
    y='test_mse', 
    hue='architecture', 
    palette='Oranges_d', 
    ax=axes[1]
)
axes[1].set_title('Testing Error (True Generalization)', fontsize=14, fontweight='bold')
axes[1].set_xlabel('Sequence Length (Days)', fontsize=12)
axes[1].set_ylabel('Test MSE', fontsize=12)
axes[1].legend(title='Hidden Layers')

# 5. Clean up the layout and show/save the plot
plt.tight_layout()

# Save the plot as an image file before showing it
plt.savefig("experiment_results_plot.png", dpi=300)
print("✅ Plot saved as 'experiment_results_plot.png'")

# Display the interactive window
plt.show()